cut.character.int = function(n, w) {
     ncm = cumsum(n);
     nwd = ncm %/% w;
     count = rle(nwd)$lengths;
     pos = cumsum(count);
     posS = pos[ - length(pos)] + 1;
     posS = c(1, posS);
     pos = rbind(posS, pos);
     return(pos);
}

